INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-01451', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '人力資源管理（humanresourcemanagement）與人事管理（personnelmanagement）兩者在意涵上 的差異，下列敘述何者錯誤？', '["人事管理是作業取向，強調本身功能的發揮；人力資源管理是策略取向，強調在組織整體經營 中所應有的配合", "人事管理重視控制，依規章管理行事；人力資源管理強調彈性，重視變革管理和人性管理", "人事管理以組織為主，目的在使成員在組織中運作，達到組織的目標；人力資源管理以成員為 主，將成員當作資源加以分析和設計，以發揮潛能和專長", "人事管理屬於預警式的管理模式，著重防患未然；人力資源管理屬於反應式的管理模式，著重 問題解決和交辦事項的執行"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01452', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '當進行員工培訓時，應包括評估訓練需求、設定培訓目標、擬定培訓計畫、實施培訓計畫、評估 培訓計畫的效能等五個步驟。就「評估培訓計畫的效能」而言，下列敘述何者正確？', '["甲機構進行社工員的在職訓練後，以問卷來衡量社工對訓練課程的喜愛及滿意程度，此為「學 習層次」的評估", "乙機構安排社工前往其他機構參訪來進行員工培訓，待社工回到工作崗位後，即由督導以觀察 法的方式來評估社工是否將訓練所學應用到工作上，此為「反應層次」的評估", "丙機構重視社工參與訓練後對機構經營績效有何正面貢獻，像是服務量是否增加、服務品質是 否改善等，此為「行為層次」的評估", "丁機構安排社工接受6小時的家庭處遇評估課程，並以測驗試題進行前後測，以了解社工學得 新知識與技能的程度，此為「學習層次」的評估"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01453', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '若機構藉由將許多小型任務合併成一個較大型的工作，讓工作更具多樣化與趣味性，以預防及減 少社工因工作而可能衍生的倦怠感，此作法稱為：', '["工作擴大化（jobenlargement）", "工作豐富化（jobenrichment）", "工作輪調（jobrotation）", "工作再設計（jobredesign）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01454', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '就有效時間管理而言，運用義大利經濟學家VilfredoPareto所提出的「80／20原則」，係屬下列 那項策略？', '["明確的目標", "有效且充分的授權", "優先次序和行動的界定", "仔細的規劃"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01455', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務機構發生重大違規事件，引發社會關注且無法依主管單位要求於特定時間內，完成內部 深入的調查報告；你是事件機構的院長，下列處理觀點何者正確？', '["應聚焦於局部，才能深入了解", "不該出現這些事件，對於機構可說毫無意義，純粹是遺憾不幸事情", "事件處理得當，可能帶給機構正面學習機會", "該保留重要內情時就保留，適度掩飾是必要的"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01456', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會服務品質要素中的確保性（Assurance）其意涵為何？', '["能力、禮貌、信譽、安全", "提供即時服務的意願", "服務的接近性", "個別化的關懷與服務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01457', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關Pfeffer&Coote（1991）對於福利體系的品質民主觀點，何者錯誤？', '["回應個別需求", "給每個人公平生活機會", "讓民眾具有做為公民顧客的權利", "一致且劃一的服務才是符合真正公平體系"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01458', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '某日間照顧中心下午載送老人返家交通車上，因接獲家屬來電要求，將該老人轉送至另外指定地 點，這樣的服務符合下列那項品質要素？', '["同理心（empathy）", "安全性（security）", "人性化（humanness）", "反應性（responsiveness）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01459', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '有關於社會服務的品質界定敘述，下列何者錯誤？', '["一種心理層面的感受狀態", "因不同時空及人事背景卻仍有相同適用", "認定上並無絕對的標準", "不論在生產、製造過程都可能出現"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01460', 'social-worker', 'social-worker-moex-109-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '目標導向績效管理中，規劃時必須考量問題與資源的狀況，係屬SMART中的那項原則？', '["簡單明確（specific）", "可測量判斷（measurable）", "可達成的（attainable）", "務實的（realistic）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:09+00:00", "source_pdf_sha1": "d2c9f9354fd0", "answer_pdf_sha1": "e73d095d3707", "source_family": "moex-gov-tw", "moex": {"exam_code": "109030", "c": "107", "s": "0603", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "109", "exam_name": "109年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
